import React, { useEffect, useState } from "react";
import { Pie, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend
);

function Analytics() {

  const [data, setData] = useState(null);

  useEffect(() => {

    async function loadData() {
      try {

        const res = await fetch("http://localhost:5000/api/analytics");
        const result = await res.json();

        console.log(result);

        setData(result);

      } catch (err) {
        console.log("Error loading analytics:", err);
      }
    }

    loadData();

  }, []);

  if (!data) {
    return <h2 style={{color:"white"}}>Loading Analytics...</h2>;
  }

  // Chart 1: Placement Distribution
  const placementPie = {
    labels: ["Placed", "Unplaced"],
    datasets: [
      {
        data: [Number(data.placedStudents), Number(data.unplacedStudents)],
        backgroundColor: ["#22c55e", "#ef4444"]
      }
    ]
  };

  // Chart 2: Placed Students
  const placedBar = {
    labels: ["Placed Students"],
    datasets: [
      {
        label: "Students",
        data: [Number(data.placedStudents)],
        backgroundColor: "#6366f1"
      }
    ]
  };

  // Chart 3: Average CGPA
  const cgpaBar = {
  labels: ["Average CGPA"],
  datasets: [
    {
      label: "CGPA",
      data: [Number(data.avgCGPA)],
      backgroundColor: ["#8b5cf6"]
    }
  ]
};

  // Chart 4: Placement Rate
  const placementRateChart = {
    labels: ["Placement Rate"],
    datasets: [
      {
        label: "Rate %",
        data: [Number(data.placementRate)],
        backgroundColor: "#22c55e"
      }
    ]
  };

  return (
    <div className="main">

      <h1>Placement Analytics</h1>

      <div className="cards">

        <div className="card">
          <h3>Total Students</h3>
          <p>{data.totalStudents}</p>
        </div>

        <div className="card">
          <h3>Placed Students</h3>
          <p>{data.placedStudents}</p>
        </div>

        <div className="card">
          <h3>Placement Rate</h3>
          <p>{data.placementRate}%</p>
        </div>

        <div className="card">
          <h3>Average CGPA</h3>
          <p>{data.avgCGPA}</p>
        </div>

      </div>

      {/* 4 Charts Layout */}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "40px",
          marginTop: "40px"
        }}
      >

        <div style={{width:"400px"}}>
          <Pie data={placementPie}/>
        </div>

        <div style={{width:"400px"}}>
          <Bar data={placedBar}/>
        </div>

        <div style={{width:"400px"}}>
          <Bar data={cgpaBar}/>
        </div>

        <div style={{width:"400px"}}>
          <Bar data={placementRateChart}/>
        </div>

      </div>

    </div>
  );
}

export default Analytics;
